import React from "react";

function AssignmentList({ assignments, submit }) {
  return (
    <div className="card">
      <h2>Assignments</h2>

      {assignments.length === 0 && (
        <p className="empty">No assignments available.</p>
      )}

      <ul>
        {assignments.map((a) => (
          <li key={a.id}>
            <div>
              <strong>{a.title}</strong>
              <div className="sub-text">{a.subject}</div>
              <div className="sub-text">Due: {a.dueDate}</div>
              <div>
                Status:{" "}
                <span
                  className={
                    a.status === "PENDING"
                      ? "status pending"
                      : "status submitted"
                  }
                >
                  {a.status}
                </span>
              </div>
            </div>

            {a.status === "PENDING" && (
              <button onClick={() => submit(a.id)}>Submit</button>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default AssignmentList;
